import torch
import numpy as np

def clean(obj):
    if isinstance(obj, dict):
        return {k: clean(v) for k, v in obj.items()}
    if isinstance(obj, list):
        return [clean(v) for v in obj]
    if isinstance(obj, tuple):
        return tuple(clean(v) for v in obj)
    if isinstance(obj, np.ndarray):
        return obj.tolist()
    if isinstance(obj, np.generic):
        return obj.item()
    return obj

ckpt = torch.load('checkpoints/model_d.pt', map_location='cpu', weights_only=False)
clean_ckpt = clean(ckpt)
torch.save(clean_ckpt, 'checkpoints/model_d.pt')
print('Cleaned and saved checkpoints/model_d.pt')
